    const node = new FfmpegAdvanced();
    const opProp = node.description.properties.find(p => p.name === 'operation');
    const ops = (opProp as { options?: Array<{ value: string }> })?.options ?? [];
    expect(ops.length).toBeGreaterThanOrEqual(16);
