// ─── Package.json validation ──────────────────────────────────────────────────

describe('package.json npm publish readiness', () => {
  // eslint-disable-next-line @typescript-eslint/no-require-imports
  const pkg = require('../../package.json') as Record<string, unknown>;

  test('has name', () => {
    expect(typeof pkg.name).toBe('string');
    expect((pkg.name as string).length).toBeGreaterThan(0);
  });

  test('has version', () => {
    expect(typeof pkg.version).toBe('string');
    expect(pkg.version).toMatch(/^\d+\.\d+\.\d+/);
  });

  test('has license', () => {
    expect(pkg.license).toBe('MIT');
  });

  test('has author', () => {
    expect(pkg.author).toBeDefined();
  });

  test('has repository', () => {
    const repo = pkg.repository as { type?: string; url?: string };
    expect(repo).toBeDefined();
    expect(repo.type).toBe('git');
    expect(repo.url).toContain('github.com');
  });

  test('has homepage', () => {
    expect(typeof pkg.homepage).toBe('string');
    expect((pkg.homepage as string)).toContain('github.com');
  });

  test('has keywords array', () => {
    expect(Array.isArray(pkg.keywords)).toBe(true);
    expect((pkg.keywords as string[]).length).toBeGreaterThan(3);
    expect((pkg.keywords as string[])).toContain('n8n-community-node-package');
  });

  test('has engines node >=18', () => {
    const engines = pkg.engines as { node?: string };
    expect(engines).toBeDefined();
    expect(engines.node).toMatch(/18/);
  });

  test('has n8n field with nodes array', () => {
    const n8n = pkg.n8n as { nodes?: string[]; credentials?: string[] };
    expect(n8n).toBeDefined();
    expect(Array.isArray(n8n.nodes)).toBe(true);
    expect(n8n.nodes!.length).toBe(4);
    n8n.nodes!.forEach(nodePath => {
      expect(nodePath).toMatch(/^dist\//);
      expect(nodePath).toMatch(/\.js$/);
    });
  });

  test('n8n nodes array covers all 4 nodes', () => {
    const n8n = pkg.n8n as { nodes?: string[] };
    const nodeNames = n8n.nodes!.map(p => path.basename(p));
    expect(nodeNames).toContain('FfmpegVideo.node.js');
    expect(nodeNames).toContain('FfmpegAudio.node.js');
    expect(nodeNames).toContain('FfmpegAnalyze.node.js');
    expect(nodeNames).toContain('FfmpegAdvanced.node.js');
  });

  test('has prepublishOnly script', () => {
    const scripts = pkg.scripts as Record<string, string>;
    expect(scripts.prepublishOnly).toBeDefined();
    expect(scripts.prepublishOnly).toContain('build');
  });

  test('has files array including dist', () => {
    const files = pkg.files as string[];
    expect(Array.isArray(files)).toBe(true);
    expect(files).toContain('dist');
  });
});

// ─── Command safety — spaces in paths ─────────────────────────────────────────

describe('quotePath in command strings', () => {
  test('quoted path with spaces is safe in shell command', () => {
    const filePath = '/my videos/clip with spaces.mp4';
    const cmd = `ffmpeg -i ${quotePath(filePath)} -c copy /tmp/out.mp4`;
    expect(cmd).toBe("ffmpeg -i '/my videos/clip with spaces.mp4' -c copy /tmp/out.mp4");
  });

  test('multiple quoted paths in one command', () => {
    const input = '/path with space/in.mp4';
    const output = '/another path/out.mp4';
    const cmd = `ffmpeg -i ${quotePath(input)} -c copy ${quotePath(output)}`;
    expect(cmd).toContain("'");
    expect(cmd).toContain(input);
    expect(cmd).toContain(output);
  });

  test('filter_complex with escaped filter value', () => {
    const text = "Hello World: it's a test";
    const escaped = escapeFilterValue(text);
    const cmd = `ffmpeg -i in.mp4 -vf "drawtext=text='${escaped}'" out.mp4`;
    expect(cmd).toContain('\\:');
    expect(cmd).toContain("\\'");
  });
});
